25: /**
26:  * Wrapper for an active accepted socket owned by the active tcp listener.
27:  */
28: class ActiveTcpSocket : public Network::ListenerFilterManager,
29:                         public Network::ListenerFilterCallbacks,
30:                         public LinkedObject<ActiveTcpSocket>,
31:                         public Event::DeferredDeletable,
32:                         Logger::Loggable<Logger::Id::conn_handler> {
33: public:
34:   ActiveTcpSocket(ActiveStreamListenerBase& listener, Network::ConnectionSocketPtr&& socket,
35:                   bool hand_off_restored_destination_connections);
36:   ~ActiveTcpSocket() override;
37: 
38:   void onTimeout();
39:   void startTimer();
40:   void unlink();
41:   void newConnection();
42: 
43:   class GenericListenerFilter
44:       : public Network::GenericListenerFilterImplBase<Network::ListenerFilter> {
45:   public:
46:     GenericListenerFilter(const Network::ListenerFilterMatcherSharedPtr& matcher,
47:                           Network::ListenerFilterPtr listener_filter)
48:         : Network::GenericListenerFilterImplBase<Network::ListenerFilter>(
49:               std::move(matcher), std::move(listener_filter)) {}
50: 
51:     Network::FilterStatus onData(Network::ListenerFilterBuffer& buffer) override {
52:       return listener_filter_->onData(buffer);
53:     }
54: 
55:     size_t maxReadBytes() const override { return listener_filter_->maxReadBytes(); }
56:   };
57:   using ListenerFilterWrapperPtr = std::unique_ptr<GenericListenerFilter>;
58: 
59:   // Network::ListenerFilterManager
60:   void addAcceptFilter(const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher,
61:                        Network::ListenerFilterPtr&& filter) override {
62:     accept_filters_.emplace_back(
63:         std::make_unique<GenericListenerFilter>(listener_filter_matcher, std::move(filter)));
64:   }
65: 
66:   // Network::ListenerFilterCallbacks
67:   Network::ConnectionSocket& socket() override { return *socket_.get(); }
68:   Event::Dispatcher& dispatcher() override;
69:   void continueFilterChain(bool success) override;
70:   void useOriginalDst(bool use_original_dst) override {
71:     hand_off_restored_destination_connections_ = use_original_dst;
72:   }
73: 
74:   void startFilterChain() { continueFilterChain(true); }
75: 
76:   void setDynamicMetadata(const std::string& name, const ProtobufWkt::Struct& value) override;
77:   void setDynamicTypedMetadata(const std::string& name, const ProtobufWkt::Any& value) override;
78:   envoy::config::core::v3::Metadata& dynamicMetadata() override {
79:     return stream_info_->dynamicMetadata();
80:   };
81:   const envoy::config::core::v3::Metadata& dynamicMetadata() const override {
82:     return stream_info_->dynamicMetadata();
83:   };
84:   StreamInfo::FilterState& filterState() override { return *stream_info_->filterState().get(); }
85:   StreamInfo::StreamInfo* streamInfo() const { return stream_info_.get(); }
86:   bool connected() const { return connected_; }
87:   bool isEndFilterIteration() const { return iter_ == accept_filters_.end(); }
88: 
89: private:
90:   void createListenerFilterBuffer();
91: 
92:   // The owner of this ActiveTcpSocket.
93:   ActiveStreamListenerBase& listener_;
94:   Network::ConnectionSocketPtr socket_;
95:   // If this field is true and valid original destination address is set, Envoy will try to hand
96:   // off the connection to the listener with the original destination address.
97:   // This defaults to value of the 'use_original_dst' field of listener proto configuration.
98:   // But it can be overridden by the listener filter by calling useOriginalDst() method.
99:   bool hand_off_restored_destination_connections_{};
100:   std::list<ListenerFilterWrapperPtr> accept_filters_;
101:   std::list<ListenerFilterWrapperPtr>::iterator iter_;
102:   Event::TimerPtr timer_;
103:   std::unique_ptr<StreamInfo::StreamInfo> stream_info_;
104:   bool connected_{false};
105: 
106:   Network::ListenerFilterBufferImplPtr listener_filter_buffer_;
107: };
