61: void ActiveTcpSocket::unlink() {
62:   auto removed = listener_.removeSocket(std::move(*this));
63:   if (removed->timer_ != nullptr) {
64:     removed->timer_->disableTimer();
65:   }
66:   // Emit logs if a connection is not established.
67:   if (!connected_ && stream_info_ != nullptr) {
68:     ActiveStreamListenerBase::emitLogs(*listener_.config_, *stream_info_);
69:   }
70:   listener_.dispatcher().deferredDelete(std::move(removed));
71: }
