185: void ActiveTcpSocket::newConnection() {
186:   connected_ = true;
187: 
188:   // Check if the socket may need to be redirected to another listener.
189:   Network::BalancedConnectionHandlerOptRef new_listener;
190: 
191:   if (hand_off_restored_destination_connections_ &&
192:       socket_->connectionInfoProvider().localAddressRestored()) {
193:     // Find a listener associated with the original destination address.
194:     new_listener =
195:         listener_.getBalancedHandlerByAddress(*socket_->connectionInfoProvider().localAddress());
196:   }
197: 
198:   // Reset the file events which are registered by listener filter.
199:   // reference https://github.com/envoyproxy/envoy/issues/8925.
200:   if (listener_filter_buffer_ != nullptr) {
201:     listener_filter_buffer_->reset();
202:   }
203: 
204:   if (new_listener.has_value()) {
205:     // Hands off connections redirected by iptables to the listener associated with the
206:     // original destination address. Pass 'hand_off_restored_destination_connections' as false to
207:     // prevent further redirection.
208:     // Leave the new listener to decide whether to execute re-balance.
209:     // Note also that we must account for the number of connections properly across both listeners.
210:     // TODO(mattklein123): See note in ~ActiveTcpSocket() related to making this accounting better.
211:     listener_.decNumConnections();
212:     new_listener.value().get().onAcceptWorker(std::move(socket_), false, false);
213:   } else {
214:     // Set default transport protocol if none of the listener filters did it.
215:     if (socket_->detectedTransportProtocol().empty()) {
216:       socket_->setDetectedTransportProtocol("raw_buffer");
217:     }
218:     accept_filters_.clear();
219:     // Create a new connection on this listener.
220:     listener_.newConnection(std::move(socket_), std::move(stream_info_));
221:   }
222: }
223: } // namespace Server
224: } // namespace Envoy
