110: ActiveTcpConnection::~ActiveTcpConnection() {
111:   ActiveStreamListenerBase::emitLogs(*active_connections_.listener_.config_, *stream_info_);
112:   auto& listener = active_connections_.listener_;
113:   listener.stats_.downstream_cx_active_.dec();
114:   listener.stats_.downstream_cx_destroy_.inc();
115:   listener.per_worker_stats_.downstream_cx_active_.dec();
116:   conn_length_->complete();
117: 
118:   // Active listener connections (not handler).
119:   listener.decNumConnections();
120: 
121:   // Active handler connections (not listener).
122:   listener.parent_.decNumConnections();
123: }
