125: void ActiveTcpConnection::onEvent(Network::ConnectionEvent event) {
126:   ENVOY_CONN_LOG(trace, "tcp connection on event {}", *connection_, static_cast<int>(event));
127:   // Any event leads to destruction of the connection.
128:   if (event == Network::ConnectionEvent::LocalClose ||
129:       event == Network::ConnectionEvent::RemoteClose) {
130:     stream_info_->setDownstreamTransportFailureReason(connection_->transportFailureReason());
131:     active_connections_.listener_.removeConnection(*this);
132:   }
133: }
