445: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
446:   downstream_headers_ = &headers;
447: 
448:   // Extract debug configuration from filter state. This is used further along to determine whether
449:   // we should append cluster and host headers to the response, and whether to forward the request
450:   // upstream.
451:   const StreamInfo::FilterStateSharedPtr& filter_state = callbacks_->streamInfo().filterState();
452:   const DebugConfig* debug_config = filter_state->getDataReadOnly<DebugConfig>(DebugConfig::key());
453: 
454:   // TODO: Maybe add a filter API for this.
455:   grpc_request_ = Grpc::Common::isGrpcRequestHeaders(headers);
456:   exclude_http_code_stats_ = grpc_request_ && config_->suppress_grpc_request_failure_code_stats_;
457: 
458:   // Only increment rq total stat if we actually decode headers here. This does not count requests
459:   // that get handled by earlier filters.
460:   stats_.rq_total_.inc();
461: 
462:   // Initialize the `modify_headers` function as a no-op (so we don't have to remember to check it
463:   // against nullptr before calling it), and feed it behavior later if/when we have cluster info
464:   // headers to append.
465:   std::function<void(Http::ResponseHeaderMap&)> modify_headers = [](Http::ResponseHeaderMap&) {};
466: 
467:   // Determine if there is a route entry or a direct response for the request.
468:   route_ = callbacks_->route();
469:   if (!route_) {
470:     stats_.no_route_.inc();
471:     ENVOY_STREAM_LOG(debug, "no route match for URL '{}'", *callbacks_, headers.getPathValue());
472: 
473:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
474:     callbacks_->sendLocalReply(Http::Code::NotFound, "", modify_headers, absl::nullopt,
475:                                StreamInfo::ResponseCodeDetails::get().RouteNotFound);
476:     return Http::FilterHeadersStatus::StopIteration;
477:   }
478: 
479:   // Determine if there is a direct response for the request.
480:   const auto* direct_response = route_->directResponseEntry();
481:   if (direct_response != nullptr) {
482:     stats_.rq_direct_response_.inc();
483:     direct_response->rewritePathHeader(headers, !config_->suppress_envoy_headers_);
484:     callbacks_->sendLocalReply(
485:         direct_response->responseCode(), direct_response->responseBody(),
486:         [this, direct_response,
487:          &request_headers = headers](Http::ResponseHeaderMap& response_headers) -> void {
488:           std::string new_uri;
489:           if (request_headers.Path()) {
490:             new_uri = direct_response->newUri(request_headers);
491:           }
492:           // See https://tools.ietf.org/html/rfc7231#section-7.1.2.
493:           const auto add_location =
494:               direct_response->responseCode() == Http::Code::Created ||
495:               Http::CodeUtility::is3xx(enumToInt(direct_response->responseCode()));
496:           if (!new_uri.empty() && add_location) {
497:             response_headers.addReferenceKey(Http::Headers::get().Location, new_uri);
498:           }
499:           direct_response->finalizeResponseHeaders(response_headers, callbacks_->streamInfo());
500:         },
501:         absl::nullopt, StreamInfo::ResponseCodeDetails::get().DirectResponse);
502:     return Http::FilterHeadersStatus::StopIteration;
503:   }
504: 
505:   // A route entry matches for the request.
506:   route_entry_ = route_->routeEntry();
507:   // If there's a route specific limit and it's smaller than general downstream
508:   // limits, apply the new cap.
509:   retry_shadow_buffer_limit_ =
510:       std::min(retry_shadow_buffer_limit_, route_entry_->retryShadowBufferLimit());
511:   if (debug_config && debug_config->append_cluster_) {
512:     // The cluster name will be appended to any local or upstream responses from this point.
513:     modify_headers = [this, debug_config](Http::ResponseHeaderMap& headers) {
514:       headers.addCopy(debug_config->cluster_header_.value_or(Http::Headers::get().EnvoyCluster),
515:                       route_entry_->clusterName());
516:     };
517:   }
518:   Upstream::ThreadLocalCluster* cluster =
519:       config_->cm_.getThreadLocalCluster(route_entry_->clusterName());
520:   if (!cluster) {
521:     stats_.no_cluster_.inc();
522:     ENVOY_STREAM_LOG(debug, "unknown cluster '{}'", *callbacks_, route_entry_->clusterName());
523: 
524:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoClusterFound);
525:     callbacks_->sendLocalReply(route_entry_->clusterNotFoundResponseCode(), "", modify_headers,
526:                                absl::nullopt,
527:                                StreamInfo::ResponseCodeDetails::get().ClusterNotFound);
528:     return Http::FilterHeadersStatus::StopIteration;
529:   }
530:   cluster_ = cluster->info();
531: 
532:   // Set up stat prefixes, etc.
533:   request_vcluster_ = route_->virtualHost().virtualCluster(headers);
534:   if (request_vcluster_ != nullptr) {
535:     callbacks_->streamInfo().setVirtualClusterName(request_vcluster_->name());
536:   }
537:   route_stats_context_ = route_entry_->routeStatsContext();
538:   ENVOY_STREAM_LOG(debug, "cluster '{}' match for URL '{}'", *callbacks_,
539:                    route_entry_->clusterName(), headers.getPathValue());
540: 
541:   if (config_->strict_check_headers_ != nullptr) {
542:     for (const auto& header : *config_->strict_check_headers_) {
543:       const auto res = FilterUtility::StrictHeaderChecker::checkHeader(headers, header);
544:       if (!res.valid_) {
545:         callbacks_->streamInfo().setResponseFlag(
546:             StreamInfo::CoreResponseFlag::InvalidEnvoyRequestHeaders);
547:         const std::string body = fmt::format("invalid header '{}' with value '{}'",
548:                                              std::string(res.entry_->key().getStringView()),
549:                                              std::string(res.entry_->value().getStringView()));
550:         const std::string details =
551:             absl::StrCat(StreamInfo::ResponseCodeDetails::get().InvalidEnvoyRequestHeaders, "{",
552:                          StringUtil::replaceAllEmptySpace(res.entry_->key().getStringView()), "}");
553:         callbacks_->sendLocalReply(Http::Code::BadRequest, body, nullptr, absl::nullopt, details);
554:         return Http::FilterHeadersStatus::StopIteration;
555:       }
556:     }
557:   }
558: 
559:   const Http::HeaderEntry* request_alt_name = headers.EnvoyUpstreamAltStatName();
560:   if (request_alt_name) {
561:     alt_stat_prefix_ = std::make_unique<Stats::StatNameDynamicStorage>(
562:         request_alt_name->value().getStringView(), config_->scope_.symbolTable());
563:     headers.removeEnvoyUpstreamAltStatName();
564:   }
565: 
566:   // See if we are supposed to immediately kill some percentage of this cluster's traffic.
567:   if (cluster_->maintenanceMode()) {
568:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamOverflow);
569:     chargeUpstreamCode(Http::Code::ServiceUnavailable, {}, true);
570:     callbacks_->sendLocalReply(
571:         Http::Code::ServiceUnavailable, "maintenance mode",
572:         [modify_headers, this](Http::ResponseHeaderMap& headers) {
573:           if (!config_->suppress_envoy_headers_) {
574:             headers.addReference(Http::Headers::get().EnvoyOverloaded,
575:                                  Http::Headers::get().EnvoyOverloadedValues.True);
576:           }
577:           // Note: append_cluster_info does not respect suppress_envoy_headers.
578:           modify_headers(headers);
579:         },
580:         absl::nullopt, StreamInfo::ResponseCodeDetails::get().MaintenanceMode);
581:     cluster_->trafficStats()->upstream_rq_maintenance_mode_.inc();
582:     return Http::FilterHeadersStatus::StopIteration;
583:   }
584: 
585:   // Support DROP_OVERLOAD config from control plane to drop certain percentage of traffic.
586:   if (checkDropOverload(*cluster, modify_headers)) {
587:     return Http::FilterHeadersStatus::StopIteration;
588:   }
589: 
590:   // Fetch a connection pool for the upstream cluster.
591:   const auto& upstream_http_protocol_options = cluster_->upstreamHttpProtocolOptions();
