905: std::unique_ptr<GenericConnPool> Filter::createConnPool(Upstream::ThreadLocalCluster& cluster,
906:                                                         Upstream::HostConstSharedPtr host) {
907:   if (host == nullptr) {
908:     return nullptr;
909:   }
910:   GenericConnPoolFactory* factory = nullptr;
911:   ProtobufTypes::MessagePtr message;
912:   if (cluster_->upstreamConfig().has_value()) {
913:     factory = Envoy::Config::Utility::getFactory<GenericConnPoolFactory>(
914:         cluster_->upstreamConfig().ref());
915:     ENVOY_BUG(factory != nullptr,
916:               fmt::format("invalid factory type '{}', failing over to default upstream",
917:                           cluster_->upstreamConfig().ref().DebugString()));
918:     if (!cluster_->upstreamConfig()->typed_config().value().empty()) {
919:       message = Envoy::Config::Utility::translateToFactoryConfig(
920:           *cluster_->upstreamConfig(), config_->factory_context_.messageValidationVisitor(),
921:           *factory);
922:     }
923:   }
924:   if (!factory) {
925:     factory = &config_->router_context_.genericConnPoolFactory();
926:   }
927: 
928:   if (!message) {
929:     message = factory->createEmptyConfigProto();
930:   }
931: 
932:   using UpstreamProtocol = Envoy::Router::GenericConnPoolFactory::UpstreamProtocol;
933:   UpstreamProtocol upstream_protocol = UpstreamProtocol::HTTP;
934:   if (route_entry_->connectConfig().has_value()) {
935:     auto method = downstream_headers_->getMethodValue();
936:     if (Http::HeaderUtility::isConnectUdpRequest(*downstream_headers_)) {
937:       upstream_protocol = UpstreamProtocol::UDP;
938:     } else if (method == Http::Headers::get().MethodValues.Connect ||
939:                (route_entry_->connectConfig()->allow_post() &&
940:                 method == Http::Headers::get().MethodValues.Post)) {
941:       // Allow POST for proxying raw TCP if it is configured.
942:       upstream_protocol = UpstreamProtocol::TCP;
943:     }
944:   }
945: 
946:   return factory->createGenericConnPool(host, cluster, upstream_protocol, route_entry_->priority(),
947:                                         callbacks_->streamInfo().protocol(), this, *message);
948: }
