950: void Filter::sendNoHealthyUpstreamResponse(absl::optional<std::string> optional_details) {
951:   callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoHealthyUpstream);
952:   chargeUpstreamCode(Http::Code::ServiceUnavailable, {}, false);
953:   absl::string_view details = (optional_details.has_value() && !optional_details->empty())
954:                                   ? absl::string_view(*optional_details)
955:                                   : StreamInfo::ResponseCodeDetails::get().NoHealthyUpstream;
956:   callbacks_->sendLocalReply(Http::Code::ServiceUnavailable, "no healthy upstream", modify_headers_,
957:                              absl::nullopt, details);
958: }
